#!/bin/bash\n\n################################################################################\n# GESTOR DE CRГ‰DITOS Y COBRANZAS - Script de CompilaciГіn para Termux (Android)\n# VersiГіn: 1.0.0\n# Plataforma: Termux en Android\n# DescripciГіn: Compila ambas versiones (Admin e Invitado) directamente en Android\n################################################################################\n\n# Colores para salida\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nMAGENTA='\\033[0;35m'\nCYAN='\\033[0;36m'\nNC='\\033[0m' # No Color\n\n# Variables\nPROJECT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nDIST_DIR=\"$PROJECT_DIR/dist\"\nAPK_DIR=\"$DIST_DIR/apks\"\nLOG_FILE=\"$DIST_DIR/build-termux.log\"\nTIMESTAMP=$(date +\"%Y-%m-%d_%H-%M-%S\")\nBUILD_REPORT=\"$DIST_DIR/build-report-termux-$TIMESTAMP.txt\"\n\n# Funciones de utilidad\nprint_header() {\n    echo -e \"${CYAN}в•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—${NC}\"\n    echo -e \"${CYAN}в•‘  GESTOR DE CRГ‰DITOS - COMPILACIГ“N PARA TERMUX (Android)   в•‘${NC}\"\n    echo -e \"${CYAN}в•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ${NC}\"\n    echo \"\"\n}\n\nprint_section() {\n    echo -e \"${MAGENTA}в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ${NC}\"\n    echo -e \"${MAGENTA}$1${NC}\"\n    echo -e \"${MAGENTA}в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ${NC}\"\n}\n\nprint_success() {\n    echo -e \"${GREEN}вњ… $1${NC}\"\n}\n\nprint_error() {\n    echo -e \"${RED}вќЊ $1${NC}\"\n}\n\nprint_warning() {\n    echo -e \"${YELLOW}вљ пёЏ  $1${NC}\"\n}\n\nprint_info() {\n    echo -e \"${BLUE}в„№пёЏ  $1${NC}\"\n}\n\nlog_message() {\n    echo \"[$TIMESTAMP] $1\" >> \"$LOG_FILE\"\n}\n\n# FunciГіn para verificar requisitos\ncheck_requirements() {\n    print_section \"рџ”Ќ Verificando Requisitos\"\n    \n    local missing_tools=()\n    \n    # Verificar Node.js\n    if ! command -v node &> /dev/null; then\n        missing_tools+=(\"Node.js\")\n        print_error \"Node.js no encontrado\"\n    else\n        local node_version=$(node --version)\n        print_success \"Node.js $node_version encontrado\"\n        log_message \"Node.js $node_version verificado\"\n    fi\n    \n    # Verificar npm\n    if ! command -v npm &> /dev/null; then\n        missing_tools+=(\"npm\")\n        print_error \"npm no encontrado\"\n    else\n        local npm_version=$(npm --version)\n        print_success \"npm $npm_version encontrado\"\n        log_message \"npm $npm_version verificado\"\n    fi\n    \n    # Verificar EAS CLI\n    if ! command -v eas &> /dev/null; then\n        print_warning \"EAS CLI no encontrado - instalando...\"\n        npm install -g eas-cli 2>&1 | tail -5\n        if command -v eas &> /dev/null; then\n            print_success \"EAS CLI instalado\"\n            log_message \"EAS CLI instalado\"\n        else\n            missing_tools+=(\"EAS CLI\")\n            print_error \"No se pudo instalar EAS CLI\"\n        fi\n    else\n        local eas_version=$(eas --version)\n        print_success \"EAS CLI $eas_version encontrado\"\n        log_message \"EAS CLI $eas_version verificado\"\n    fi\n    \n    # Verificar git\n    if ! command -v git &> /dev/null; then\n        print_warning \"git no encontrado (opcional)\"\n    else\n        print_success \"git encontrado\"\n    fi\n    \n    # Si faltan herramientas, mostrar instrucciones\n    if [ ${#missing_tools[@]} -gt 0 ]; then\n        print_error \"Faltan las siguientes herramientas: ${missing_tools[*]}\"\n        print_info \"Para instalar en Termux, ejecuta:\"\n        echo -e \"${YELLOW}pkg install -y nodejs npm git${NC}\"\n        return 1\n    fi\n    \n    print_success \"Todos los requisitos estГЎn satisfechos\"\n    return 0\n}\n\n# FunciГіn para instalar dependencias\ninstall_dependencies() {\n    print_section \"рџ“¦ Instalando Dependencias del Proyecto\"\n    \n    cd \"$PROJECT_DIR\" || exit 1\n    \n    if [ -d \"node_modules\" ]; then\n        print_info \"node_modules ya existe - limpiando cachГ©\"\n        npm cache clean --force 2>&1 | tail -3\n    fi\n    \n    print_info \"Instalando dependencias con npm...\"\n    if npm install 2>&1 | tee -a \"$LOG_FILE\"; then\n        print_success \"Dependencias instaladas correctamente\"\n        return 0\n    else\n        print_error \"Error al instalar dependencias\"\n        return 1\n    fi\n}\n\n# FunciГіn para compilar versiГіn Admin\ncompile_admin() {\n    print_section \"рџ”§ Compilando VersiГіn ADMIN\"\n    \n    cd \"$PROJECT_DIR\" || exit 1\n    \n    # Asegurar que app.json es la versiГіn Admin\n    if [ -f \"app.json\" ]; then\n        print_info \"Usando configuraciГіn Admin (app.json)\"\n    else\n        print_error \"app.json no encontrado\"\n        return 1\n    fi\n    \n    print_info \"Iniciando compilaciГіn con EAS...\"\n    print_warning \"Nota: Esta es una compilaciГіn local. Puede tomar 15-30 minutos.\"\n    \n    if eas build --platform android --local 2>&1 | tee -a \"$LOG_FILE\"; then\n        print_success \"APK Admin compilado exitosamente\"\n        \n        # Buscar el APK generado\n        local apk_file=$(find . -name \"*.apk\" -type f -newer \"$LOG_FILE\" 2>/dev/null | head -1)\n        if [ -n \"$apk_file\" ]; then\n            mkdir -p \"$APK_DIR\"\n            cp \"$apk_file\" \"$APK_DIR/gestor-creditos-admin-$TIMESTAMP.apk\"\n            print_success \"APK copiado a: $APK_DIR/gestor-creditos-admin-$TIMESTAMP.apk\"\n            log_message \"APK Admin compilado: $apk_file\"\n        fi\n        return 0\n    else\n        print_error \"Error al compilar versiГіn Admin\"\n        return 1\n    fi\n}\n\n# FunciГіn para compilar versiГіn Invitado\ncompile_guest() {\n    print_section \"рџ‘Ґ Compilando VersiГіn INVITADO\"\n    \n    cd \"$PROJECT_DIR\" || exit 1\n    \n    # Cambiar a configuraciГіn Guest\n    if [ -f \"app-guest.json\" ]; then\n        print_info \"Cambiando a configuraciГіn Invitado (app-guest.json)\"\n        cp app.json app.json.backup\n        cp app-guest.json app.json\n    else\n        print_error \"app-guest.json no encontrado\"\n        return 1\n    fi\n    \n    print_info \"Iniciando compilaciГіn con EAS...\"\n    print_warning \"Nota: Esta es una compilaciГіn local. Puede tomar 15-30 minutos.\"\n    \n    if eas build --platform android --local 2>&1 | tee -a \"$LOG_FILE\"; then\n        print_success \"APK Invitado compilado exitosamente\"\n        \n        # Buscar el APK generado\n        local apk_file=$(find . -name \"*.apk\" -type f -newer \"$LOG_FILE\" 2>/dev/null | head -1)\n        if [ -n \"$apk_file\" ]; then\n            mkdir -p \"$APK_DIR\"\n            cp \"$apk_file\" \"$APK_DIR/gestor-creditos-guest-$TIMESTAMP.apk\"\n            print_success \"APK copiado a: $APK_DIR/gestor-creditos-guest-$TIMESTAMP.apk\"\n            log_message \"APK Invitado compilado: $apk_file\"\n        fi\n        \n        # Restaurar configuraciГіn original\n        if [ -f \"app.json.backup\" ]; then\n            mv app.json.backup app.json\n            print_info \"ConfiguraciГіn original restaurada\"\n        fi\n        return 0\n    else\n        print_error \"Error al compilar versiГіn Invitado\"\n        # Restaurar configuraciГіn original\n        if [ -f \"app.json.backup\" ]; then\n            mv app.json.backup app.json\n        fi\n        return 1\n    fi\n}\n\n# FunciГіn para limpiar archivos temporales\nclean_temp() {\n    print_section \"рџ§№ Limpiando Archivos Temporales\"\n    \n    cd \"$PROJECT_DIR\" || exit 1\n    \n    rm -f app.json.backup\n    rm -rf .expo\n    npm cache clean --force 2>&1 | tail -2\n    \n    print_success \"Archivos temporales limpiados\"\n}\n\n# FunciГіn para generar reporte\ngenerate_report() {\n    print_section \"рџ“Љ Generando Reporte\"\n    \n    cat > \"$BUILD_REPORT\" << EOF\nв•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—\nв•‘  GESTOR DE CRГ‰DITOS - REPORTE DE COMPILACIГ“N (Termux)     в•‘\nв•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ\n\nFecha: $TIMESTAMP\nPlataforma: Termux (Android)\nDirectorio: $PROJECT_DIR\n\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\nрџ“± VERSIONES COMPILADAS\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\nвњ… VersiГіn Admin\n   - Acceso completo\n   - GestiГіn de deudores\n   - CreaciГіn de pagos\n   - Reportes y grГЎficos\n   - GestiГіn de usuarios\n\nвњ… VersiГіn Invitado\n   - Solo lectura\n   - VisualizaciГіn de deudores\n   - Consulta de pagos\n   - VisualizaciГіn de reportes\n   - Acceso limitado\n\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\nрџ“Ѓ ARCHIVOS GENERADOS\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\nAPKs:\n$(ls -lh $APK_DIR/*.apk 2>/dev/null | awk '{print \"  \" $9 \" (\" $5 \")\"}' || echo \"  No hay APKs generados\")\n\nLogs:\n  $LOG_FILE\n  $BUILD_REPORT\n\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\nрџљЂ PRГ“XIMOS PASOS\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\n1. Los APKs estГЎn listos en: $APK_DIR\n2. Transfiere los APKs a tu dispositivo\n3. Abre el administrador de archivos\n4. Navega a la carpeta de descargas\n5. Toca cada APK para instalar\n6. ВЎComienza a usar!\n\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\nрџ“ћ SOPORTE\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\nEmail: support@gestorcreditos.com\nDocumentaciГіn: Consulta los archivos .md\nLogs: $LOG_FILE\n\nEOF\n    \n    print_success \"Reporte generado: $BUILD_REPORT\"\n}\n\n# FunciГіn para mostrar ayuda\nshow_help() {\n    cat << EOF\nGESTOR DE CRГ‰DITOS - Script de CompilaciГіn para Termux\n\nUso: $0 [OPCIГ“N]\n\nOpciones:\n  all         Compilar ambas versiones (predeterminado)\n  admin       Solo versiГіn Admin\n  guest       Solo versiГіn Invitado\n  clean       Limpiar archivos temporales\n  help        Mostrar esta ayuda\n\nEjemplos:\n  $0              # Compilar ambas versiones\n  $0 admin        # Solo Admin\n  $0 guest        # Solo Invitado\n  $0 clean        # Limpiar\n  $0 help         # Mostrar ayuda\n\nRequisitos en Termux:\n  pkg install -y nodejs npm git\n\nEOF\n}\n\n# FunciГіn principal\nmain() {\n    local action=\"${1:-all}\"\n    \n    # Crear directorio de logs\n    mkdir -p \"$DIST_DIR\" \"$APK_DIR\"\n    \n    # Inicializar log\n    echo \"=== CompilaciГіn Iniciada: $TIMESTAMP ===\" > \"$LOG_FILE\"\n    \n    print_header\n    print_info \"AcciГіn: $action\"\n    print_info \"Directorio: $PROJECT_DIR\"\n    print_info \"Logs: $LOG_FILE\"\n    echo \"\"\n    \n    # Verificar requisitos\n    if ! check_requirements; then\n        print_error \"No se pueden satisfacer los requisitos\"\n        return 1\n    fi\n    echo \"\"\n    \n    # Instalar dependencias\n    if ! install_dependencies; then\n        print_error \"Error al instalar dependencias\"\n        return 1\n    fi\n    echo \"\"\n    \n    # Ejecutar acciГіn\n    case \"$action\" in\n        all)\n            if compile_admin && compile_guest; then\n                print_success \"Ambas versiones compiladas exitosamente\"\n                clean_temp\n                generate_report\n                return 0\n            else\n                print_error \"Error al compilar versiones\"\n                return 1\n            fi\n            ;;\n        admin)\n            if compile_admin; then\n                print_success \"VersiГіn Admin compilada exitosamente\"\n                clean_temp\n                generate_report\n                return 0\n            else\n                print_error \"Error al compilar Admin\"\n                return 1\n            fi\n            ;;\n        guest)\n            if compile_guest; then\n                print_success \"VersiГіn Invitado compilada exitosamente\"\n                clean_temp\n                generate_report\n                return 0\n            else\n                print_error \"Error al compilar Invitado\"\n                return 1\n            fi\n            ;;\n        clean)\n            clean_temp\n            print_success \"Limpieza completada\"\n            return 0\n            ;;\n        help)\n            show_help\n            return 0\n            ;;\n        *)\n            print_error \"AcciГіn desconocida: $action\"\n            show_help\n            return 1\n            ;;\n    esac\n}\n\n# Ejecutar funciГіn principal\nmain \"$@\"\nexit $?\n
